1	import { useCallback, useMemo, useState } from 'react';
2	import {
3	  KeyboardAvoidingView,
4	  Platform,
5	  SafeAreaView,
6	  ScrollView,
7	  StyleSheet,
8	  Text,
9	  TextInput,
10	  type TextInputProps,
11	  View,
12	} from 'react-native';
13	import { useRouter } from 'expo-router';
14	import { colors, radii, shadows, spacing } from '@/design/tokens';
15	import { textStyles } from '@/design/typography';
16	import { ButtonPrimary } from '@/components/primitives/Button';
17	import { SkeletonCard } from '@/components/primitives/SkeletonCard';
18	import { useToast } from '@/components/primitives/Toast';
19	import { useAuth, type AuthUser } from '@/lib/auth';
20	import { supabase } from '@/lib/supabase';
21	
22	// US-034 — Creator signup. Username + at least one handle (TikTok and/or
23	// Instagram). Submit calls auth-signup-creator; the edge function holds the
24	// request open up to APIFY_WAIT_SECS (60s) while it dispatches scrapes, so
25	// the submitting state renders "Pulling your stats…" with skeleton cards for
26	// each supplied handle. On success the JWT + user row is handed to the
27	// AuthProvider and we jump to the creator tab group. Inline 409 handling
28	// mirrors the US-033 lister pattern; USERNAME_TAKEN pins to the username
29	// field, HANDLE_TAKEN falls through to a toast because the edge function
30	// does not say which platform conflicted.
31	
32	type FieldKey = 'username' | 'tiktok' | 'instagram';
33	type FieldErrors = Partial<Record<FieldKey, string>>;
34	
35	const USERNAME_RE = /^[a-zA-Z0-9_]{3,32}$/;
36	const HANDLE_RE = /^[a-zA-Z0-9_.]{1,30}$/;
37	
38	type FieldValues = { username: string; tiktok: string; instagram: string };
39	
40	function stripAt(value: string): string {
41	  return value.trim().replace(/^@+/, '').trim();
42	}
43	
44	function clientValidate(v: FieldValues): FieldErrors {
45	  const errs: FieldErrors = {};
46	  const u = v.username.trim();
47	  const tt = stripAt(v.tiktok);
48	  const ig = stripAt(v.instagram);
49	
50	  if (!u) errs.username = 'Username is required';
51	  else if (!USERNAME_RE.test(u)) errs.username = '3–32 letters, numbers, or underscores';
52	
53	  if (tt && !HANDLE_RE.test(tt)) errs.tiktok = 'Letters, numbers, underscores, or dots';
54	  if (ig && !HANDLE_RE.test(ig)) errs.instagram = 'Letters, numbers, underscores, or dots';
55	
56	  if (!tt && !ig) {
57	    const msg = 'Add at least one handle';
58	    errs.tiktok = msg;
59	    errs.instagram = msg;
60	  }
61	
62	  return errs;
63	}
64	
65	type SignupSuccess = {
66	  token: string;
67	  user_id: string;
68	  role: 'creator';
69	  metrics_status?: Record<string, unknown>;
70	};
71	
72	export default function SignupCreator() {
73	  const router = useRouter();
74	  const { signIn } = useAuth();
75	  const { show: showToast } = useToast();
76	
77	  const [username, setUsername] = useState('');
78	  const [tiktok, setTiktok] = useState('');
79	  const [instagram, setInstagram] = useState('');
80	  const [touched, setTouched] = useState<Partial<Record<FieldKey, boolean>>>({});
81	  const [serverErrors, setServerErrors] = useState<FieldErrors>({});
82	  const [submitting, setSubmitting] = useState(false);
83	
84	  const clientErrors = useMemo(
85	    () => clientValidate({ username, tiktok, instagram }),
86	    [username, tiktok, instagram],
87	  );
88	
89	  const visibleErrors: FieldErrors = {
90	    username: serverErrors.username ?? (touched.username ? clientErrors.username : undefined),
91	    tiktok: serverErrors.tiktok ?? (touched.tiktok ? clientErrors.tiktok : undefined),
92	    instagram:
93	      serverErrors.instagram ?? (touched.instagram ? clientErrors.instagram : undefined),
94	  };
95	
96	  const markTouched = useCallback((key: FieldKey) => {
97	    setTouched((t) => (t[key] ? t : { ...t, [key]: true }));
98	  }, []);
99	
100	  const updateField = useCallback(
101	    (key: FieldKey, setter: (s: string) => void) => (next: string) => {
102	      setter(next);
103	      setServerErrors((prev) => (prev[key] ? { ...prev, [key]: undefined } : prev));
104	    },
105	    [],
106	  );
107	
108	  const onSubmit = useCallback(async () => {
109	    setTouched({ username: true, tiktok: true, instagram: true });
110	    const errs = clientValidate({ username, tiktok, instagram });
111	    if (Object.keys(errs).length > 0) return;
112	
113	    const tiktokHandle = stripAt(tiktok);
114	    const instagramHandle = stripAt(instagram);
115	
116	    setServerErrors({});
117	    setSubmitting(true);
118	    // Track success separately so the `finally` block doesn't flip
119	    // `submitting` back to false on the way out — swapping from
120	    // PullingStatsState back to the form would flash the form for a frame
121	    // before the router.replace navigation unmounts the screen.
122	    let didSucceed = false;
123	    try {
124	      const { data, error } = await supabase.functions.invoke<SignupSuccess>(
125	        'auth-signup-creator',
126	        {
127	          body: {
128	            username: username.trim(),
129	            ...(tiktokHandle ? { tiktok_handle: tiktokHandle } : {}),
130	            ...(instagramHandle ? { instagram_handle: instagramHandle } : {}),
131	          },
132	        },
133	      );
134	
135	      if (error) {
136	        const ctx = (error as { context?: unknown }).context;
137	        if (
138	          ctx &&
139	          typeof ctx === 'object' &&
140	          'status' in ctx &&
141	          typeof (ctx as { json?: unknown }).json === 'function'
142	        ) {
143	          const res = ctx as Response;
144	          let body: { error?: string } = {};
145	          try {
146	            body = (await res.json()) as { error?: string };
147	          } catch {
148	            // non-JSON body; fall through to generic toast
149	          }
150	          if (res.status === 409 && body.error === 'USERNAME_TAKEN') {
151	            setServerErrors({ username: 'Username already taken' });
152	            return;
153	          }
154	          if (res.status === 409 && body.error === 'HANDLE_TAKEN') {
155	            // Edge function does not identify which platform conflicted; the
156	            // creator profile screen (US-035) has the add/unlink flow that
157	            // can surface the specific collision.
158	            showToast({
159	              message: 'That handle is already linked to another account.',
160	              variant: 'error',
161	            });
162	            return;
163	          }
164	          if (res.status === 422 && body.error === 'HANDLE_REQUIRED') {
165	            const msg = 'Add at least one handle';
166	            setServerErrors({ tiktok: msg, instagram: msg });
167	            return;
168	          }
169	        }
170	        showToast({ message: 'Signup failed. Please try again.', variant: 'error' });
171	        return;
172	      }
173	
174	      if (!data) {
175	        showToast({ message: 'Signup failed. Please try again.', variant: 'error' });
176	        return;
177	      }
178	
179	      const nowIso = new Date().toISOString();
180	      const nextUser: AuthUser = {
181	        id: data.user_id,
182	        username: username.trim(),
183	        email: null,
184	        role: 'creator',
185	        created_at: nowIso,
186	        updated_at: nowIso,
187	        deleted_at: null,
188	      };
189	      didSucceed = true;
190	      signIn(data.token, nextUser);
191	      showToast({ message: 'Welcome', variant: 'success' });
192	      router.replace('/(creator)/feed');
193	    } catch (err) {
194	      console.error('Creator signup threw', err);
195	      showToast({ message: 'Signup failed. Please try again.', variant: 'error' });
196	    } finally {
197	      if (!didSucceed) setSubmitting(false);
198	    }
199	  }, [username, tiktok, instagram, signIn, showToast, router]);
200	
201	  if (submitting) {
202	    return <PullingStatsState tiktok={stripAt(tiktok)} instagram={stripAt(instagram)} />;
203	  }
204	
205	  return (
206	    <SafeAreaView style={styles.container}>
207	      <KeyboardAvoidingView
208	        behavior={Platform.OS === 'ios' ? 'padding' : undefined}
209	        style={styles.flex}
210	      >
211	        <ScrollView
212	          contentContainerStyle={styles.scrollContent}
213	          keyboardShouldPersistTaps="handled"
214	        >
215	          <View style={styles.header}>
216	            <Text style={[textStyles.display, styles.title]}>Creator signup</Text>
217	            <Text style={[textStyles.body, styles.subtitle]}>
218	              Pick a username and add at least one handle — we&apos;ll pull your stats.
219	            </Text>
220	          </View>
221	
222	          <View style={styles.fields}>
223	            <Field
224	              label="Username"
225	              value={username}
226	              onChange={updateField('username', setUsername)}
227	              onBlur={() => markTouched('username')}
228	              autoCapitalize="none"
229	              autoCorrect={false}
230	              autoComplete="username"
231	              placeholder="sarah_films"
232	              error={visibleErrors.username}
233	              testID="creator-signup-username"
234	            />
235	            <Field
236	              label="TikTok handle"
237	              value={tiktok}
238	              onChange={updateField('tiktok', setTiktok)}
239	              onBlur={() => markTouched('tiktok')}
240	              autoCapitalize="none"
241	              autoCorrect={false}
242	              autoComplete="off"
243	              keyboardType="default"
244	              placeholder="@sarahfilms"
245	              mono
246	              error={visibleErrors.tiktok}
247	              testID="creator-signup-tiktok"
248	            />
249	            <Field
250	              label="Instagram handle"
251	              value={instagram}
252	              onChange={updateField('instagram', setInstagram)}
253	              onBlur={() => markTouched('instagram')}
254	              autoCapitalize="none"
255	              autoCorrect={false}
256	              autoComplete="off"
257	              keyboardType="default"
258	              placeholder="@sarahfilms"
259	              mono
260	              error={visibleErrors.instagram}
261	              testID="creator-signup-instagram"
262	            />
263	          </View>
264	
265	          <ButtonPrimary
266	            label="Continue"
267	            onPress={onSubmit}
268	            loading={submitting}
269	            disabled={submitting}
270	            accessibilityLabel="Continue creator signup"
271	            testID="creator-signup-submit"
272	          />
273	        </ScrollView>
274	      </KeyboardAvoidingView>
275	    </SafeAreaView>
276	  );
277	}
278	
279	function PullingStatsState({
280	  tiktok,
281	  instagram,
282	}: {
283	  tiktok: string;
284	  instagram: string;
285	}) {
286	  return (
287	    <SafeAreaView style={styles.container}>
288	      <View style={styles.loadingContent}>
289	        <View style={styles.header}>
290	          <Text style={[textStyles.display, styles.title]}>Pulling your stats…</Text>
291	          <Text style={[textStyles.body, styles.subtitle]}>
292	            This can take up to a minute while we fetch your public profile.
293	          </Text>
294	        </View>
295	        <View style={styles.skeletons}>
296	          {tiktok ? (
297	            <SkeletonCard height={96} testID="creator-signup-skeleton-tiktok" />
298	          ) : null}
299	          {instagram ? (
300	            <SkeletonCard height={96} testID="creator-signup-skeleton-instagram" />
301	          ) : null}
302	        </View>
303	      </View>
304	    </SafeAreaView>
305	  );
306	}
307	
308	type FieldProps = {
309	  label: string;
310	  value: string;
311	  onChange: (next: string) => void;
312	  onBlur?: () => void;
313	  autoCapitalize?: TextInputProps['autoCapitalize'];
314	  autoCorrect?: boolean;
315	  autoComplete?: TextInputProps['autoComplete'];
316	  keyboardType?: TextInputProps['keyboardType'];
317	  placeholder?: string;
318	  error?: string;
319	  mono?: boolean;
320	  testID?: string;
321	};
322	
323	function Field({
324	  label,
325	  value,
326	  onChange,
327	  onBlur,
328	  autoCapitalize,
329	  autoCorrect,
330	  autoComplete,
331	  keyboardType,
332	  placeholder,
333	  error,
334	  mono,
335	  testID,
336	}: FieldProps) {
337	  const hasError = !!error;
338	  return (
339	    <View style={styles.field}>
340	      <Text style={[textStyles.caption, styles.label]}>{label}</Text>
341	      <View style={[styles.inputWrap, shadows.hard, hasError && styles.inputWrapError]}>
342	        <TextInput
343	          value={value}
344	          onChangeText={onChange}
345	          onBlur={onBlur}
346	          autoCapitalize={autoCapitalize}
347	          autoCorrect={autoCorrect}
348	          autoComplete={autoComplete}
349	          keyboardType={keyboardType}
350	          placeholder={placeholder}
351	          placeholderTextColor={colors.ink40}
352	          style={[mono ? textStyles.mono : textStyles.body, styles.input]}
353	          accessibilityLabel={label}
354	          testID={testID}
355	        />
356	      </View>
357	      <Text
358	        style={[textStyles.caption, styles.errorText, !hasError && styles.errorHidden]}
359	        accessibilityLiveRegion="polite"
360	        importantForAccessibility={hasError ? 'yes' : 'no-hide-descendants'}
361	      >
362	        {error ?? ''}
363	      </Text>
364	    </View>
365	  );
366	}
