1	import { useCallback, useMemo, useState } from 'react';
2	import {
3	  KeyboardAvoidingView,
4	  Platform,
5	  SafeAreaView,
6	  ScrollView,
7	  StyleSheet,
8	  Text,
9	  TextInput,
10	  type TextInputProps,
11	  View,
12	} from 'react-native';
13	import { useRouter } from 'expo-router';
14	import { colors, radii, shadows, spacing } from '@/design/tokens';
15	import { textStyles } from '@/design/typography';
16	import { ButtonPrimary } from '@/components/primitives/Button';
17	import { useToast } from '@/components/primitives/Toast';
18	import { useAuth, type AuthUser } from '@/lib/auth';
19	import { supabase } from '@/lib/supabase';
20	
21	// US-033 — Lister (Company) signup. Three fields → auth-signup-lister edge
22	// function; 409 USERNAME_TAKEN / EMAIL_TAKEN surface inline on the conflicting
23	// field, other errors fall through to a toast. Design: docs/design.md §2.1
24	// Company Profile (captures username + email + org name; website_url is
25	// optional per the edge-function contract and deferred out of v1's core signup
26	// to keep the form to the story AC's three fields).
27	
28	type FieldKey = 'username' | 'email' | 'orgName';
29	type FieldErrors = Partial<Record<FieldKey, string>>;
30	
31	const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
32	const USERNAME_RE = /^[a-zA-Z0-9_]{3,32}$/;
33	
34	type FieldValues = { username: string; email: string; orgName: string };
35	
36	function clientValidate(v: FieldValues): FieldErrors {
37	  const errs: FieldErrors = {};
38	  const u = v.username.trim();
39	  const e = v.email.trim();
40	  const o = v.orgName.trim();
41	  if (!u) errs.username = 'Username is required';
42	  else if (!USERNAME_RE.test(u)) errs.username = '3–32 letters, numbers, or underscores';
43	  if (!e) errs.email = 'Email is required';
44	  else if (!EMAIL_RE.test(e)) errs.email = 'Enter a valid email';
45	  if (!o) errs.orgName = 'Company name is required';
46	  return errs;
47	}
48	
49	type SignupSuccess = { token: string; user_id: string; role: 'lister' };
50	
51	export default function SignupLister() {
52	  const router = useRouter();
53	  const { signIn } = useAuth();
54	  const { show: showToast } = useToast();
55	
56	  const [username, setUsername] = useState('');
57	  const [email, setEmail] = useState('');
58	  const [orgName, setOrgName] = useState('');
59	  const [touched, setTouched] = useState<Partial<Record<FieldKey, boolean>>>({});
60	  const [serverErrors, setServerErrors] = useState<FieldErrors>({});
61	  const [submitting, setSubmitting] = useState(false);
62	
63	  const clientErrors = useMemo(
64	    () => clientValidate({ username, email, orgName }),
65	    [username, email, orgName],
66	  );
67	
68	  // Server-originated inline errors always win; client errors only surface once
69	  // the user has touched a field (avoids yelling before they've typed anything).
70	  const visibleErrors: FieldErrors = {
71	    username: serverErrors.username ?? (touched.username ? clientErrors.username : undefined),
72	    email: serverErrors.email ?? (touched.email ? clientErrors.email : undefined),
73	    orgName: serverErrors.orgName ?? (touched.orgName ? clientErrors.orgName : undefined),
74	  };
75	
76	  const markTouched = useCallback((key: FieldKey) => {
77	    setTouched((t) => (t[key] ? t : { ...t, [key]: true }));
78	  }, []);
79	
80	  const updateField = useCallback(
81	    (key: FieldKey, setter: (s: string) => void) => (next: string) => {
82	      setter(next);
83	      setServerErrors((prev) => (prev[key] ? { ...prev, [key]: undefined } : prev));
84	    },
85	    [],
86	  );
87	
88	  const onSubmit = useCallback(async () => {
89	    setTouched({ username: true, email: true, orgName: true });
90	    const errs = clientValidate({ username, email, orgName });
91	    if (Object.keys(errs).length > 0) return;
92	
93	    setServerErrors({});
94	    setSubmitting(true);
95	    try {
96	      const { data, error } = await supabase.functions.invoke<SignupSuccess>(
97	        'auth-signup-lister',
98	        {
99	          body: {
100	            username: username.trim(),
101	            email: email.trim(),
102	            org_name: orgName.trim(),
103	          },
104	        },
105	      );
106	
107	      if (error) {
108	        const ctx = (error as { context?: unknown }).context;
109	        if (
110	          ctx &&
111	          typeof ctx === 'object' &&
112	          'status' in ctx &&
113	          typeof (ctx as { json?: unknown }).json === 'function'
114	        ) {
115	          const res = ctx as Response;
116	          let body: { error?: string } = {};
117	          try {
118	            // supabase-js v2 does not pre-read the error Response, so reading
119	            // directly is safe; `.clone()` would just add a second stream-state
120	            // failure surface without any benefit here.
121	            body = (await res.json()) as { error?: string };
122	          } catch {
123	            // non-JSON body; fall through to generic toast
124	          }
125	          if (res.status === 409 && body.error === 'USERNAME_TAKEN') {
126	            setServerErrors({ username: 'Username already taken' });
127	            return;
128	          }
129	          if (res.status === 409 && body.error === 'EMAIL_TAKEN') {
130	            setServerErrors({ email: 'Email already in use' });
131	            return;
132	          }
133	        }
134	        showToast({ message: 'Signup failed. Please try again.', variant: 'error' });
135	        return;
136	      }
137	
138	      if (!data) {
139	        showToast({ message: 'Signup failed. Please try again.', variant: 'error' });
140	        return;
141	      }
142	
143	      // The edge function response carries only token + user_id + role. We
144	      // construct the AuthUser row shape client-side; the real timestamps live
145	      // in Postgres and will be read by later queries (profile screen, etc.).
146	      const nowIso = new Date().toISOString();
147	      const nextUser: AuthUser = {
148	        id: data.user_id,
149	        username: username.trim(),
150	        email: email.trim(),
151	        role: 'lister',
152	        created_at: nowIso,
153	        updated_at: nowIso,
154	        deleted_at: null,
155	      };
156	      signIn(data.token, nextUser);
157	      showToast({ message: 'Welcome', variant: 'success' });
158	      router.replace('/(lister)/dashboard');
159	    } catch (err) {
160	      console.error('Lister signup threw', err);
161	      showToast({ message: 'Signup failed. Please try again.', variant: 'error' });
162	    } finally {
163	      setSubmitting(false);
164	    }
165	  }, [username, email, orgName, signIn, showToast, router]);
166	
167	  return (
168	    <SafeAreaView style={styles.container}>
169	      <KeyboardAvoidingView
170	        behavior={Platform.OS === 'ios' ? 'padding' : undefined}
171	        style={styles.flex}
172	      >
173	        <ScrollView
174	          contentContainerStyle={styles.scrollContent}
175	          keyboardShouldPersistTaps="handled"
176	        >
177	          <View style={styles.header}>
178	            <Text style={[textStyles.display, styles.title]}>Company signup</Text>
179	            <Text style={[textStyles.body, styles.subtitle]}>
180	              Pick a handle, tell us who you are, and start posting bounties.
181	            </Text>
182	          </View>
183	
184	          <View style={styles.fields}>
185	            <Field
186	              label="Username"
187	              value={username}
188	              onChange={updateField('username', setUsername)}
189	              onBlur={() => markTouched('username')}
190	              autoCapitalize="none"
191	              autoCorrect={false}
192	              autoComplete="username"
193	              placeholder="acme_media"
194	              error={visibleErrors.username}
195	              testID="lister-signup-username"
196	            />
197	            <Field
198	              label="Email"
199	              value={email}
200	              onChange={updateField('email', setEmail)}
201	              onBlur={() => markTouched('email')}
202	              autoCapitalize="none"
203	              autoCorrect={false}
204	              keyboardType="email-address"
205	              autoComplete="email"
206	              placeholder="hello@acme.co"
207	              error={visibleErrors.email}
208	              testID="lister-signup-email"
209	            />
210	            <Field
211	              label="Company name"
212	              value={orgName}
213	              onChange={updateField('orgName', setOrgName)}
214	              onBlur={() => markTouched('orgName')}
215	              autoCapitalize="words"
216	              autoComplete="organization"
217	              placeholder="Acme Media"
218	              error={visibleErrors.orgName}
219	              testID="lister-signup-orgname"
220	            />
221	          </View>
222	
223	          <ButtonPrimary
