99	Deno.serve(async (req) => {
100	  if (req.method === "OPTIONS") {
101	    return new Response(null, { status: 204, headers: corsHeaders });
102	  }
103	  if (req.method !== "POST") {
104	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
105	  }
106	
107	  let body: SignupRequest;
108	  try {
109	    body = await req.json();
110	  } catch {
111	    return jsonResponse(400, { error: "INVALID_JSON" });
112	  }
113	
114	  const username =
115	    isString(body.username) && body.username.trim().length > 0
116	      ? body.username.trim()
117	      : null;
118	  const tiktokHandle = normalizeHandle(body.tiktok_handle);
119	  const instagramHandle = normalizeHandle(body.instagram_handle);
120	
121	  if (!username) {
122	    return jsonResponse(400, { error: "INVALID_REQUEST" });
123	  }
124	  if (!tiktokHandle && !instagramHandle) {
125	    return jsonResponse(422, { error: "HANDLE_REQUIRED" });
126	  }
127	
128	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
129	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
130	  if (!supabaseUrl || !serviceRoleKey) {
131	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
132	  }
133	
134	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
135	    auth: { persistSession: false, autoRefreshToken: false },
136	  });
137	
138	  const { data, error } = await supabase.rpc("auth_signup_creator", {
139	    p_username: username,
140	    p_tiktok_handle: tiktokHandle,
141	    p_instagram_handle: instagramHandle,
142	  });
143	
144	  if (error) {
145	    console.error("auth_signup_creator rpc error", error);
146	    return jsonResponse(500, { error: "DB_ERROR" });
147	  }
148	
149	  const result = data as { user_id?: string; error?: string } | null;
150	  if (result?.error === "USERNAME_TAKEN") {
151	    return jsonResponse(409, { error: "USERNAME_TAKEN" });
152	  }
153	  if (result?.error === "HANDLE_TAKEN") {
154	    return jsonResponse(409, { error: "HANDLE_TAKEN" });
155	  }
156	  if (!result?.user_id) {
157	    console.error("auth_signup_creator returned unexpected shape", result);
158	    return jsonResponse(500, { error: "DB_ERROR" });
159	  }
160	
161	  const userId = result.user_id;
162	  const sessionId = crypto.randomUUID();
163	  let token: string;
164	  try {
165	    token = await signJwt({
166	      sub: userId,
167	      role: "creator",
168	      session_id: sessionId,
169	    });
170	  } catch (err) {
171	    console.error("signJwt failed", err);
172	    return jsonResponse(500, { error: "JWT_ERROR" });
173	  }
174	
175	  const metricsStatus = await dispatchApifyRuns({
176	    supabase,
177	    supabaseUrl,
178	    userId,
179	    tiktokHandle,
180	    instagramHandle,
181	  });
182	
183	  return jsonResponse(200, {
184	    token,
185	    user_id: userId,
186	    role: "creator",
187	    metrics_status: metricsStatus,
188	  });
189	});
